39	TEST_CASE("narrow QEMU-virt region maps GPA 0x80010000 to file offset 0x10000")
40	{
41	  const auto path = unique_tmp_path("write");
42	  constexpr std::size_t kSize = 8 * 1024 * 1024;
43	  constexpr uint64_t kBaseGpa = 0x80000000;
44	
45	  MmapBacking backing(path, kSize, kBaseGpa);
46	  CHECK(backing.base_gpa() == kBaseGpa);
47	  CHECK(backing.size() == kSize);
48	
49	  SimpleMemory<32> mem{
50	    "mem", MemoryRegion{kBaseGpa, kBaseGpa + kSize - 1},
51	    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
52	                 SimpleMemory<32>::INVALID_ADDRESS},
53	    backing.span()};
54	
55	  std::array<uint8_t, 8> pattern{0xde, 0xad, 0xbe, 0xef,
56	                                  0xca, 0xfe, 0xba, 0xbe};
57	  tlm::tlm_generic_payload gp;
58	  gp.set_command(tlm::TLM_WRITE_COMMAND);
59	  gp.set_address(kBaseGpa + 0x10000);
60	  gp.set_data_ptr(pattern.data());
61	  gp.set_data_length(pattern.size());
62	  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
63	  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
64	  mem.b_transport(gp, delay);
65	  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
66	
67	  const int fd = ::open(path.c_str(), O_RDONLY);
68	  REQUIRE(fd >= 0);
69	  void* p = ::mmap(nullptr, kSize, PROT_READ, MAP_SHARED, fd, 0);
70	  REQUIRE(p != MAP_FAILED);
71	  auto* file_bytes = static_cast<const uint8_t*>(p);
72	  for (std::size_t i = 0; i < pattern.size(); ++i)
73	    CHECK(file_bytes[0x10000 + i] == pattern[i]);
74	  ::munmap(p, kSize);
75	  ::close(fd);
76	  std::filesystem::remove(path);
77	}
