79	TEST_CASE("bytes pre-placed at file offset 0x10000 read back as GPA 0x80010000")
80	{
81	  const auto path = unique_tmp_path("read");
82	  constexpr std::size_t kSize = 8 * 1024 * 1024;
83	  constexpr uint64_t kBaseGpa = 0x80000000;
84	
85	  MmapBacking backing(path, kSize, kBaseGpa);
86	  backing.span()[0x10000 + 0] = 0xa5;
87	  backing.span()[0x10000 + 1] = 0x5a;
88	
89	  SimpleMemory<32> mem{
90	    "mem", MemoryRegion{kBaseGpa, kBaseGpa + kSize - 1},
91	    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
92	                 SimpleMemory<32>::INVALID_ADDRESS},
93	    backing.span()};
94	
95	  std::array<uint8_t, 2> out{};
96	  tlm::tlm_generic_payload gp;
97	  gp.set_command(tlm::TLM_READ_COMMAND);
98	  gp.set_address(kBaseGpa + 0x10000);
99	  gp.set_data_ptr(out.data());
100	  gp.set_data_length(out.size());
101	  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
102	  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
