51	class parser
52	{
53	public:
54	  using string_handler = std::function<void(std::string_view)>;
55	  using flag_handler = std::function<void()>;
56	
57	  struct handler
58	  {
59	    bool takes_value = false;
60	    string_handler value_fn{};
61	    flag_handler flag_fn{};
62	  };
63	
64	  std::unordered_map<std::string_view, handler> longopts;
65	  std::unordered_map<char, handler> shortopts;
66	
67	  string_handler posarg_handler = [](auto) {};
68	  string_handler unknown_handler = [](const std::string_view s) {
69	    throw std::runtime_error{"Unrecognized option: " + std::string{s}};
70	  };
71	
72	  auto longopt(const std::string_view k, const string_handler& h) -> parser&
73	  {
74	    longopts.emplace(k, handler{.takes_value = true, .value_fn = h});
75	    return *this;
76	  }
77	
78	  auto longflag(const std::string_view k, const flag_handler& h) -> parser&
79	  {
80	    longopts.emplace(k, handler{.takes_value = false, .flag_fn = h});
81	    return *this;
82	  }
83	
84	  auto shortopt(const char c, const string_handler& h) -> parser&
85	  {
86	    shortopts.emplace(c, handler{.takes_value = true, .value_fn = h});
87	    return *this;
88	  }
89	
90	  auto shortflag(const char c, const flag_handler& h) -> parser&
91	  {
92	    shortopts.emplace(c, handler{.takes_value = false, .flag_fn = h});
93	    return *this;
94	  }
95	
96	  auto posarg(const string_handler& h) -> parser&
97	  {
98	    posarg_handler = h;
99	    return *this;
100	  }
101	
102	  auto unknown(const string_handler& h) -> parser&
103	  {
104	    unknown_handler = h;
105	    return *this;
106	  }
107	
108	  void parse(const std::span<const std::string_view> args) const
109	  {
110	    if (args.empty())
111	      return;
112	
113	    for (auto it = args.begin() + 1; it != args.end(); ++it) {
114	      const auto s = *it;
115	
116	      if (s == "--") {
117	        for (it = std::next(it); it != args.end(); ++it)
118	          posarg_handler(*it);
119	        break;
120	      } else if (s.starts_with("--")) {
121	        const auto eq = s.find('=', 2);
122	        const auto key =
123	          eq == std::string::npos ? s.substr(2, eq) : s.substr(2, eq - 2);
124	
125	        const auto hit = longopts.find(key);
126	        if (hit == std::end(longopts)) {
127	          unknown_handler(s.substr(0, eq));
128	          continue;
129	        }
130	
131	        const auto& opt = hit->second;
132	        if (!opt.takes_value) {
133	          opt.flag_fn();
134	        } else if (eq != std::string::npos) { // --key=value
135	          opt.value_fn(s.substr(eq + 1));
136	        } else if (++it != args.end()) { // --key value
137	          opt.value_fn(*it);
138	        } else {
139	          throw std::runtime_error{"No value given for --" + std::string{key}};
140	        }
141	      } else if (s.starts_with("-")) {
142	        for (auto cit = s.begin() + 1; cit != s.end(); ++cit) {
143	          const char c = *cit;
144	          const auto hit = shortopts.find(c);
145	
146	          if (hit == std::end(shortopts)) {
147	            unknown_handler(std::string("-") + c);
148	            continue;
149	          }
150	
151	          const auto& opt = hit->second;
152	          if (!opt.takes_value) {
153	            opt.flag_fn();
154	          } else if (const auto value = std::next(cit); value != s.end()) {
155	            opt.value_fn(s.substr(value - s.begin()));
156	            cit = std::prev(s.end());
157	          } else if (++it != args.end()) { // -o value
158	            opt.value_fn(*it);
159	          } else {
160	            throw std::runtime_error{"No value given for -" + std::string{c}};
161	          }
162	        }
163	      } else {
164	        posarg_handler(s);
165	      }
166	    }
167	  }
168	};
169	
170	#endif
